        kind: 'radio_label',
        label_id: label.id || null,
        label_for: chosen.id,
        label_text: (label.textContent || '').trim(),
        cx: Math.round(rect.left + rect.width / 2),
        cy: Math.round(rect.top + rect.height / 2),
